(window.webpackJsonp=window.webpackJsonp||[]).push([[34],{661:function(n,p){n.exports="\x3c!--\ntitle: 05-进程\nsort:\n--\x3e \n\n> 了解系统正在忙些什么\n\n## ps\n\n- `ps x`\n\n  > TTY: 进程的控制终端\n  >\n  > STAT: 状态\n  >\n  > `Run-Sleep-Dot-sTop-Z`\n  >\n  > 运行-睡眠-不可中断睡眠(等待IO)-停止-终止\n  >\n  > `<` 高优先级进程`N`低优先级进程\n  \n- `ps aux`\n\n  > | 标题  | 含义                           |\n  > | ----- | ------------------------------ |\n  > | USER  | 用户ID[进程所有者]             |\n  > | %CPU  | CPU使用率                      |\n  > | %MEM  | 内存使用率                     |\n  > | VSZ   | 虚拟内存                       |\n  > | RSS   | 进程占用物理内存大小(单位: KB) |\n  > | START | 进程启动时间                   |\n\n### top\n\n> 按照进程活动顺序显示进程列表\n\n| 行号 | 字段     | 含义                        |\n| ---- | -------- | --------------------------- |\n| 1    | top      | 程序名                      |\n|      | 16:43:49 | 当前时间                    |\n|      | up 6:06  | 计算机正常运行时间          |\n|      | 1 users  | 一个用户登录系统            |\n| 2    | Task     | 进程数目信息                |\n| 3    | %Cpu(s)  | Cpu运行信息                 |\n|      | us/sy/ni | 用户/内核/低优先级应用/占用 |\n|      | id/wa    | 空闲/等待IO                 |\n\n"}}]);